focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm\" placeholder=\"••••••••\"></div><button class=\"w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500\">เข้าสู่ระบบ</button><a href=\"#\" class=\"mt-4 text-sm text-blue-600 hover:text-blue-500\">ลืมรหัสผ่าน?</a></div>", "previewClasses": "p-4 bg-gray-100 flex items-center justify-center h-64"}, {"id": "b", "label": "แบบที่ 2", "content": "<div class=\"flex flex-col items-center justify-center p-8 bg-white shadow-lg rounded-xl max-w-sm mx-auto\"><h2 class=\"text-2xl font-bold mb-6 text-gray-800\">เข้าสู่ระบบ</h2><div class=\"w-full mb-4\"><label for=\"email-b\" class=\"block text-sm font-medium text-gray-700 mb-1\">อีเมล</label><input type=\"email\" id=\"email-b\" class=\"mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm\" placeholder=\"you@example.com\"></div><div class=\"w-full mb-4\"><label for=\"password-b\" class=\"block text-sm font-medium text-gray-700 mb-1\">รหัสผ่าน</label><input type=\"password\" id=\"password-b\" class=\"mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm\" placeholder=\"••••••••\"></div><div class=\"w-full mb-6 flex items-center justify-between\"><div class=\"flex items-center\"><input id=\"remember-me\" name=\"remember-me\" type=\"checkbox\" class=\"h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded\"><label for=\"remember-me\" class=\"ml-2 block text-sm text-gray-900\">จดจำฉันไว้</label></div><a href=\"#\" class=\"text-sm text-blue-600 hover:text-blue-500\">ลืมรหัสผ่าน?</a></div><button class=\"w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white 